class CombinationIterator:

    def __init__(self, characters: str, combinationLength: int):
        self.combinations = []
        self.index = 0
        self.generate_combinations(characters, combinationLength, "")

    def next(self) -> str:
        if self.hasNext():
            result = self.combinations[self.index]
            self.index += 1
            return result
        return ""

    def hasNext(self) -> bool:
        return self.index < len(self.combinations)

    def generate_combinations(self, characters: str, combinationLength: int, current_combination: str):
        if len(current_combination) == combinationLength:
            self.combinations.append(current_combination)
            return
        for char in characters:
            if char not in current_combination:
                self.generate_combinations(characters, combinationLength, current_combination + char)
```

